import React from "react";
import "./About.css";

export default function About() {
  const mainImg =
    "https://static.vecteezy.com/system/resources/thumbnails/019/050/491/small/a-girl-sitting-and-writing-a-diet-plan-weight-loss-concept-eat-food-that-is-good-for-the-body-such-as-fruits-and-vegetables-free-photo.jpg";

  const miniCards = [
    {
      img: "https://images.pexels.com/photos/1640777/pexels-photo-1640777.jpeg?auto=compress&cs=tinysrgb&w=600",
      title: "Healthy Meals",
      price: "$15",
    },
    {
      img: "https://images.pexels.com/photos/1640773/pexels-photo-1640773.jpeg?auto=compress&cs=tinysrgb&w=600",
      title: "Balanced Plate",
      price: "$25",
    },
    {
      img: "https://images.pexels.com/photos/406152/pexels-photo-406152.jpeg?auto=compress&cs=tinysrgb&w=600",
      title: "Fresh Ingredients",
      price: "$35",
    },
    {
      img: "https://images.pexels.com/photos/1640777/pexels-photo-1640777.jpeg?auto=compress&cs=tinysrgb&w=600",
      title: "Nutritious Snacks",
      price: "$15",
    },
  ];

  return (
    <div className="about-page">
      <div className="about-card">
        {/* LEFT SIDE TEXT */}
        <div className="about-content">
          <span className="tag">ABOUT US 🌿</span>

          <h1>Taste the Best that Improves Your Health</h1>
          <p>
            We believe in providing clean, healthy and delicious food that fuels
            your body and fits your lifestyle. Our nutrition specialists create
            meal plans that support weight loss, fitness, and overall wellness.
          </p>

          <div className="about-buttons">
            <button className="btn-primary">Learn More</button>
            <button className="btn-secondary">Our Mission</button>
          </div>
        </div>

        {/* RIGHT SIDE IMAGE */}
        <div className="about-image-box">
          <img src={mainImg} alt="diet" />
        </div>
      </div>

      {/* MINI CARDS */}
      <div className="mini-card-row">
        {miniCards.map((c, i) => (
          <div className="mini-card" key={i}>
            <img src={c.img} alt={c.title} />
            <h3>{c.title}</h3>
            <p>{c.price}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
